use warehouse compute_small;

create database bench_idx;
create schema bench_idx.seed1;

create table bench_idx.seed1.customers (id INT, name STRING, email STRING, city STRING, birthday DATE);
create table bench_idx.seed1.products (id INT, name STRING, category STRING, price_cents INT);
create table bench_idx.seed1.orders (id INT, customer_id INT, product_id INT, quantity INT, note STRING, ordered_at TIMESTAMP);
create table bench_idx.seed1.payments (id INT, order_id INT, customer_id INT, method STRING, status STRING, amount_cents INT);
create table bench_idx.seed1.shipments (id INT, order_id INT, carrier STRING, status STRING, tracking_code STRING);

